    salHelpTitle:'Pomoc z tym kalkulatorem', salHelpDesc:'Jak korzystać z kalkulatora podatkowego',
    salHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Oblicz ile płacisz podatku i jaki jest Twój dochód netto'],['Wynagrodzenie roczne brutto','Wpisz roczne wynagrodzenie przed opodatkowaniem. To kwota z umowy o pracę.'],['Klasa podatkowa','Klasa 1 jest standardem. Klasa 2 dotyczy małżonka z niskim dochodem. Osoby samozatrudnione mają oddzielne zasady.'],['Gmina/region','Wybierz „Standard" dla całego kraju (22% podatek zwykły). Finnmark/Nord-Troms ma niższą stawkę (18,5%).'],['— JAK CZYTAĆ WYNIKI —',''],['Wynagrodzenie roczne netto','Kwota, którą otrzymujesz po potrąceniu wszystkich podatków.'],['Podatek łączny','Suma podatku zwykłego, podatku progresywnego i składki na ubezpieczenie społeczne.'],['Efektywna stawka podatkowa','Procent wynagrodzenia brutto przeznaczony na podatki. Większość płaci 25-35%.'],['Składka na ubezpieczenie społeczne','7,6% dochodu brutto. Finansuje system ubezpieczeń (emerytury, zasiłki chorobowe).'],['Podatek progresywny','Podatek rosnący w progach. Niski dochód = niska stawka. Wysoki dochód = wyższa stawka.'],['— WARTO WIEDZIEĆ —',''],['Odliczenie minimalne','Automatycznie otrzymujesz 46% wynagrodzenia (maks. 95 700 kr) jako odliczenie.'],['Ulga osobista','Każdy otrzymuje 114 540 kr wolne od podatku.'],['Odliczenie odsetek','Odsetki od kredytów (hipoteka, kredyt studencki) dają 22% zwrotu podatku.']],
    uttakHelpTitle:'Jak korzystać z kalkulatora wypłat', uttakHelpDesc:'Przewodnik krok po kroku po opodatkowaniu wypłat',
    uttakHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Oblicz podatek od wypłaty aktywów z firmy'],['Typ działalności','Wybierz ENK (jednoosobowa działalność) lub AS (spółka z o.o.). ENK: opodatkowanie bezpośrednie, AS: podwójne opodatkowanie (spółka + dywidenda).'],['Wartość rynkowa','Aktywo wyceniane jest według wartości rynkowej w momencie wypłaty — jakbyś „sprzedał" je sobie.'],['Wartość podatkowa','Zamortyzowana wartość w księgach. Różnica między wartością rynkową a podatkową to zysk.'],['Udział wypłacony','Jeśli wypłacasz tylko część aktywa na użytek prywatny, wpisz procent.'],['— JAK CZYTAĆ WYNIKI —',''],['Zysk z wypłaty','Wartość rynkowa minus wartość podatkowa, skorygowana o udział wypłacony.'],['Zwykły podatek dochodowy','22% zysku — dotyczy zarówno ENK, jak i AS.'],['Składka na ubezpieczenie (ENK)','10,8% dochodu osobistego, jeśli wypłata stanowi dochód z działalności.'],['Podatek progresywny (ENK)','Podatek progresywny zależny od poziomu dochodu.'],['Podatek korporacyjny + dywidendowy (AS)','Zysk jest najpierw opodatkowany 22% w spółce, potem jako dywidenda u akcjonariusza.'],['— WARTO WIEDZIEĆ —',''],['Częsty błąd','Wielu zapomina, że wypłata powoduje opodatkowanie — nie jest zwolnione z podatku tylko dlatego, że jesteś właścicielem firmy.'],['Odliczenie osłonowe (AS)','Zmniejsza podatek od dywidendy. Oparte na cenie nabycia akcji × stopa osłonowa.']],
    utdelingHelpTitle:'Jak korzystać z kalkulatora efektywnego podatku od dystrybucji', utdelingHelpDesc:'Przewodnik krok po kroku po modelu akcjonariusza i przedsiębiorcy',
    utdelingHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Porównaj obciążenie podatkowe między AS i ENK'],['Forma prawna','Wybierz AS (model akcjonariusza) lub ENK (model przedsiębiorcy), aby zobaczyć różnicę.'],['Zysk','Wpisz zysk do wypłaty właścicielowi.'],['Odliczenie osłonowe','Tylko dla AS — zmniejsza podatek od dywidendy. Oparte na cenie nabycia × stopa osłonowa.'],['— JAK CZYTAĆ WYNIKI —',''],['Podatek łączny','Suma wszystkich warstw podatkowych — podatek korporacyjny + dywidendowy (AS) lub dochodowy + ubezpieczenie + progresywny (ENK).'],['Netto dla właściciela','Kwota pozostająca właścicielowi po wszystkich podatkach.'],['Efektywna stawka podatkowa','Udział zysku przeznaczony na podatki. AS: typowo ~51,5%. ENK: do ~50,6%.'],['— WARTO WIEDZIEĆ —',''],['Zasada symetrii','Wybór formy prawnej sam w sobie nie powinien dawać korzyści podatkowej — oba modele dają w przybliżeniu równe łączne opodatkowanie.'],['AS: podwójne opodatkowanie','Najpierw 22% podatku korporacyjnego, potem podatek od dywidendy (22% × współczynnik podwyższenia 1,72 = 37,84%).'],['ENK: opodatkowanie bezpośrednie','Zysk jest opodatkowany bezpośrednio jako dochód osobisty — 22% + ubezpieczenie społeczne + podatek progresywny.']],
    morHelpTitle:'Pomoc z tym kalkulatorem', morHelpDesc:'Jak korzystać z kalkulatora kredytów hipotecznych',
    morHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Oblicz miesięczne raty i całkowity koszt kredytu'],['Typ kredytu','Annuitetowy = równe miesięczne raty. Seryjny = malejące raty.'],['Kwota kredytu','Kwota pożyczona z banku. Potrzebujesz min. 10% wkładu własnego.'],['Oprocentowanie','Stopa procentowa banku. W styczniu 2026 r. średnia wynosi ok. 5,1% zmiennego.'],['Okres kredytu','Liczba lat spłaty. W Norwegii typowo 25-30 lat.'],['— JAK CZYTAĆ WYNIKI —',''],['Miesięczna rata','Kwota płacona bankowi co miesiąc (odsetki + kapitał).'],['Łącznie spłacone','Suma wszystkich płatności. Pokazuje rzeczywisty koszt kredytu.'],['Łączne odsetki','Ile płacisz odsetek w sumie. Często więcej niż sam kredyt przez 25-30 lat.'],['Efektywne oprocentowanie','Rzeczywisty roczny koszt z opłatami. Użyj do porównania ofert.'],['Rok 1 odsetki/kapitał','Podział w pierwszym roku. Przy annuitecie większość idzie na odsetki na początku.'],['— WARTO WIEDZIEĆ —',''],['Annuitetowy vs. seryjny','Annuitetowy: przewidywalny. Seryjny: tańszy łącznie, ale wyższy na początku.'],['Odliczenie podatkowe od odsetek','Otrzymujesz 22% kosztów odsetkowych jako zwrot podatku.'],['Test warunków skrajnych','Bank sprawdza, czy wytrzymasz oprocentowanie min. 7%.']],
    vatHelpTitle:'Pomoc z tym kalkulatorem', vatHelpDesc:'Jak korzystać z kalkulatora VAT',
    vatHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Oblicz ceny z i bez VAT'],['Kwota','Wpisz kwotę, dla której chcesz obliczyć VAT.'],['Stawka VAT','Wybierz: 25% (standard), 15% (żywność), 12% (transport/hotel/kino) lub 0% (zwolnione).'],['Kwota jest','Wybierz, czy kwota zawiera VAT, czy nie.'],['— JAK CZYTAĆ WYNIKI —',''],['Cena z VAT','Całkowita cena płacona przez klienta, z podatkiem.'],['Bez VAT','Cena bez podatku — przychód sprzedawcy.'],['Kwota VAT','Podatek do zapłaty państwu.'],['Stawka %','Stawka VAT użyta w obliczeniu.'],['— WARTO WIEDZIEĆ —',''],['25% to stawka standardowa','Większość towarów i usług ma 25% VAT. Żywność: 15%. Transport, hotele, kino: 12%.'],['Eksport jest zwolniony','Eksport ma 0% VAT, ale firma zachowuje prawo do odliczenia VAT naliczonego.'],['Kalkulator korekt','Pod kalkulatorem VAT znajduje się kalkulator korekt dla aktywów kapitałowych.']],
    adjHelpTitle:'Jak korzystać z kalkulatora korekt', adjHelpDesc:'Przewodnik krok po kroku po korekcie VAT',
    adjHelpRows: [['— JAK KORZYSTAĆ Z KALKULATORA —','Oblicz korektę naliczonego VAT przy zmianie użytkowania'],['Typ aktywa kapitałowego','Nieruchomości mają 10-letni okres korekty, maszyny/sprzęt 5 lat.'],['Łączny naliczony VAT','Kwota VAT, którą pierwotnie odliczyłeś przy nabyciu aktywa.'],['Lata użytkowania','Liczba pełnych lat od odliczenia VAT.'],['Stary udział (%)','Udział użytkowania objętego VAT PRZED zmianą.'],['Nowy udział (%)','Udział użytkowania objętego VAT PO zmianie.'],['— JAK CZYTAĆ WYNIKI —',''],['Zwrot / zwiększone odliczenie','Zmniejszone użytkowanie objęte VAT = zwrot. Zwiększone = możesz odliczyć więcej.'],['Korekta roczna','Kwota korygowana w każdym pozostałym roku.'],['Pozostałe lata','Liczba lat pozostałych w okresie korekty.'],['— WARTO WIEDZIEĆ —',''],['Wartość progowa','Naliczony VAT musi przekraczać 100 000 kr (nieruchomości) lub 50 000 kr (maszyny) dla obowiązku korekty.'],['Zmiana użytkowania','Typowa: zmiana z wynajmu objętego VAT na wynajem zwolniony lub odwrotnie.']],
